    if (total_bytes == 0) {
        /* Nothing to parse, but we still allocate a tiny buffer to satisfy the API */
        total_bytes = 1;
    }

    char *buffer = (char *)malloc(total_bytes);
    if (buffer == NULL) {
        return -1;               /* allocation failure */
    }
    /* Initialise the buffer with zeroes – this also pads missing fields. */
    memset(buffer, 0, total_bytes);

    /* Parse each CSV record and copy the fields into the fixed‑size buffer */
    char *buf_ptr = buffer;
    for (int rec = 0; rec < record_count; ++rec) {
        /* If a record is missing we treat it as an empty record (already zeroed). */
        if (csv_data[rec] == NULL) {
            /* Skip the whole record: the buffer is already zeroed. */
            buf_ptr += sum_field_sizes;
            continue;
        }

        /* strtok modifies the string, so work on a temporary copy. */
        size_t line_len = strlen(csv_data[rec]);
        char *line_copy = (char *)malloc(line_len + 1);
        if (line_copy == NULL) {
            free(buffer);
            return -1;
        }
        strcpy(line_copy, csv_data[rec]);

        char *token = strtok(line_copy, ",");
        for (int f = 0; f < num_fields; ++f) {
            if (token != NULL) {
                size_t token_len = strlen(token);
                size_t copy_len = (token_len >= (size_t)field_sizes[f]) ?
                                  (size_t)field_sizes[f] : token_len;

                /* Copy the token (truncate if necessary). */
                memcpy(buf_ptr, token, copy_len);

                /* Pad the remaining part of the field with NUL bytes. */
                if (copy_len < (size_t)field_sizes[f]) {
                    memset(buf_ptr + copy_len, 0, field_sizes[f] - copy_len);
                }

                /* Advance the buffer pointer by the full field width. */
                buf_ptr += field_sizes[f];

                /* Move to the next token. */
                token = strtok(NULL, ",");
            } else {
                /* No more tokens – leave the remaining fields zeroed. */
                memset(buf_ptr, 0, field_sizes[f]);
                buf_ptr += field_sizes[f];
            }
        }

        /* If there are more tokens than fields, ignore the extras. */
        free(line_copy);
    }

    /* Return the allocated buffer to the caller. */
    *parsed_buffer = buffer;
    return 0;
}

